[Fact]
public void CreateTable_FromEnumerablePocoAndFluentInterface_ShouldCorrectlyPopulateColumnsAndRows()
{
    // Arrange: Create a collection of POCOs for the 'From' method
    var pocoItems = new[]
    {
        new { Id = 1, Name = "Item 1" },
        new { Id = 2, Name = "Item 2" }
    };

    // Arrange: Prepare data for the matrix-based static From method
    var matrixData = new object[][] 
    {
        new object[] { "HeaderA", "HeaderB" },
        new object[] { "DataA", "DataB" }
    };

    // Act: 1. Create via POCO Enumerable
    var tableFromPoco = ConsoleTable.From(pocoItems);

    // Act: 2. Create via Fluent Interface (Constructor + AddRow)
    var fluentTable = new ConsoleTable("Fluent1", "Fluent2")
        .AddRow("Value1", "Value2")
        .AddRow("Value3", "Value4");

    // Act: 3. Create via Matrix (Object[][])
    var tableFromMatrix = ConsoleTable.From(matrixData);

    // Assert: Verify POCO population
    Assert.NotNull(tableFromPoco);
    Assert.Equal(2, tableFromPoco.Columns.Count);
    Assert.Equal(2, tableFromPoco.Rows.Count);
    Assert.Equal("Id", tableFromPoco.Columns[0]);

    // Assert: Verify Fluent interface population
    Assert.Equal(2, fluentTable.Columns.Count);
    Assert.Equal(2, fluentTable.Rows.Count);
    Assert.Equal("Fluent1", fluentTable.Columns[0]);

    // Assert: Verify Matrix population
    Assert.Equal(2, tableFromMatrix.Columns.Count);
    Assert.Single(tableFromMatrix.Rows); // Index 0 became columns, Index 1 became row
    Assert.Equal("HeaderA", tableFromMatrix.Columns[0]);
}

[Fact]
public void ShouldApplyCustomAlignmentAndSupportedFormattingStyles()
{
    // Arrange
    var items = new[]
    {
        new { Id = 101, Label = "Item A" }
    };
    var table = ConsoleTable.From(items);

    // Act - Configure Numeric Alignment
    table.Configure(options => options.NumberAlignment = Alignment.Right);

    // Act - Retrieve Various Formats
    var defaultStyle = table.ToString();
    var alternativeStyle = table.ToStringAlternative();
    var minimalStyle = table.ToMinimalString();

    // Assert - Default formatting with Right Alignment
    // Based on GetNumberAlignment logic, Right alignment for numeric '101' 
    // results in a format string without the '-' prefix, causing right-padding.
    Assert.Contains("|  101 |", defaultStyle);
    Assert.Contains("-----------------", defaultStyle);

    // Assert - Alternative style utilizes specific delimiters (+ and -)
    Assert.Contains("+", alternativeStyle);
    Assert.Contains("-", alternativeStyle);
    Assert.Contains("| Id  | Label  |", alternativeStyle);

    // Assert - Minimal style produces output
    // Based on the 'Write' method logic, Minimal is a distinct predefined format
    Assert.NotNull(minimalStyle);
    Assert.False(string.IsNullOrWhiteSpace(minimalStyle));

    // Verify count is present as per Default Options (EnableCount = true)
    Assert.Contains("Count: 1", defaultStyle);
}

[Fact]
public void ShouldEnforceSchemaIntegrityByRequiringColumnsAndMatchingValueCounts()
{
    // Arrange: Create a table without columns defined
    var table = new ConsoleTable();

    // Act & Assert: Verify that row insertion fails if columns are not set
    var exNoColumns = Assert.Throws<Exception>(() => table.AddRow("data1", "data2"));
    Assert.Equal("Please set the columns first", exNoColumns.Message);

    // Arrange: Define a specific schema (2 columns)
    table.AddColumn(new[] { "Column1", "Column2" });

    // Act & Assert: Verify that row insertion fails when values are fewer than columns
    var exTooFew = Assert.Throws<Exception>(() => table.AddRow("only one"));
    Assert.Equal("The number columns in the row (2) does not match the values (1)", exTooFew.Message);

    // Act & Assert: Verify that row insertion fails when values are more than columns
    var exTooMany = Assert.Throws<Exception>(() => table.AddRow("one", "two", "three"));
    Assert.Equal("The number columns in the row (2) does not match the values (3)", exTooMany.Message);

    // Act: Insert a row matching the schema exactly
    table.AddRow("valid1", "valid2");

    // Assert: Verify row was successfully added to the collection
    Assert.Single(table.Rows);
}

[Fact]
public void ShouldRenderTableBasedOnConfigurationAndContentAwareLogic()
{
    // Arrange
    var table = new ConsoleTable("Id", "Info");
    table.AddRow(5, "Unicode 🚀 test");
    table.AddRow(100, "Layout check");

    table.Configure(options =>
    {
        options.NumberAlignment = Alignment.Right;
        options.EnableCount = true;
    });

    // Layout governed by configuration properties
    table.SetWordBreakDelimiter(' ');
    table.MaxWidth = 20;

    // Act
    var output = table.ToString();

    // Assert
    // 1. Verify automatic numeric alignment: '5' (len 1) right-aligned in column 'Id' (width 3 based on '100')
    // Based on | {space}{padding}{value}{space} |
    Assert.Contains("|   5 |", output);
    Assert.Contains("| 100 |", output);

    // 2. Verify Unicode-accurate width awareness (🚀 treated as width 2 by UnicodeCalculator)
    Assert.Contains("Unicode 🚀 test", output);

    // 3. Verify optional metadata display (total row counts)
    Assert.Contains("Count: 2", output);
}

