        public void ShouldRightAlignNumericValuesAndSuppressCountWhenConfigured()
        {
            // Arrange
            var data = new[] 
            {
                new { ID = 1, Value = 100 }
            };

            var table = ConsoleTable.From(data)
                .Configure(o =>
                {
                    o.NumberAlignment = Alignment.Right;
                    o.EnableCount = false;
                });

            // Act
            var result = table.ToString();

            // Assert
            // For the 'ID' column (length 2), the value '1' should be right-aligned (preceded by a space).
            // For the 'Value' column (length 5), the value '100' should be right-aligned (preceded by two spaces).
            // Output line for data should look like: |  1 |   100 |
            Assert.Contains("|  1 |   100 |", result);

            // Verify that the count footer (e.g., "Count: 1") is absent from the output string.
            Assert.DoesNotContain("Count:", result);
        }

[Fact]
public void FromDictionary_ShouldMapNestedDictionaryKeysToHeadersAndRows()
{
    // Arrange
    var data = new Dictionary<string, Dictionary<string, object>>
    {
        {
            "RowA", new Dictionary<string, object>
            {
                { "Col1", "Value1" },
                { "Col2", 100 }
            }
        },
        {
            "RowB", new Dictionary<string, object>
            {
                { "Col1", "Value2" },
                { "Col2", 200 }
            }
        }
    };

    // Act
    var table = ConsoleTable.FromDictionary(data);

    // Assert
    // FromDictionary inserts an empty string at index 0 for the row header column
    Assert.Equal(3, table.Columns.Count);
    Assert.Equal("", table.Columns[0]);
    Assert.Equal("Col1", table.Columns[1]);
    Assert.Equal("Col2", table.Columns[2]);

    // Verify Row A data mapping
    Assert.Equal("RowA", table.Rows[0][0]);
    Assert.Equal("Value1", table.Rows[0][1]);
    Assert.Equal(100, table.Rows[0][2]);

    // Verify Row B data mapping
    Assert.Equal("RowB", table.Rows[1][0]);
    Assert.Equal("Value2", table.Rows[1][1]);
    Assert.Equal(200, table.Rows[1][2]);
}

[Fact]
public void TableFormattingShouldAccountForUnicodeWidthAndSupportNumericRightAlignment()
{
    // Arrange
    // 'User' class is defined in the source context and used in existing tests.
    var users = new List<User>
    {
        new() { Name = "Apple 🍎", Age = 5 },
        new() { Name = "汉字 (CJK)", Age = 100 }
    };

    // Act
    // Configure right-alignment for numeric types as per the business rule.
    var result = ConsoleTable
        .From(users)
        .Configure(o => o.NumberAlignment = Alignment.Right)
        .ToString();

    // Assert
    // Visual widths calculation:
    // "Name" (4), "Apple 🍎" (8), "汉字 (CJK)" (10). Max Column Width = 10.
    // "Age" (3), 5 (1), 100 (3). Max Column Width = 3.

    // The Name header (string) remains left-aligned by default.
    // "Name" + 6 spaces = 10 content width.
    Assert.Contains("| Name       | Age |", result);

    // "Apple 🍎" (visual width 8) + 2 spaces = 10 content width.
    // "5" (visual width 1) right-aligned in width 3 = 2 spaces + "5".
    Assert.Contains("| Apple 🍎   |   5 |", result);

    // "汉字 (CJK)" (visual width 10) + 0 spaces = 10 content width.
    // "100" (visual width 3) right-aligned in width 3 = 0 spaces + "100".
    Assert.Contains("| 汉字 (CJK) | 100 |", result);
}

[Fact]
public void ShouldSupportDataIngestionFromMultipleStandardDotNetStructures()
{
    // Arrange - Prepare IEnumerable data source
    var enumerableData = new[] 
    {
        new { ID = 1, Name = "Item 1" },
        new { ID = 2, Name = "Item 2" }
    };

    // Arrange - Prepare Dictionary data source
    var dictionaryData = new Dictionary<string, Dictionary<string, object>>
    {
        { "Row1", new Dictionary<string, object> { { "ID", 1 }, { "Name", "Item 1" } } },
        { "Row2", new Dictionary<string, object> { { "ID", 2 }, { "Name", "Item 2" } } }
    };

    // Arrange - Prepare DataTable data source
    var dataTable = new System.Data.DataTable();
    dataTable.Columns.Add("ID");
    dataTable.Columns.Add("Name");
    dataTable.Rows.Add(1, "Item 1");
    dataTable.Rows.Add(2, "Item 2");

    // Act - Ingest from all three sources
    var tableFromEnumerable = ConsoleTable.From(enumerableData);
    var tableFromDictionary = ConsoleTable.FromDictionary(dictionaryData);
    var tableFromDataTable = ConsoleTable.From(dataTable);

    // Assert - Verify that columns were correctly identified/created for all sources
    Assert.NotNull(tableFromEnumerable);
    Assert.Contains("ID", tableFromEnumerable.Columns);
    Assert.Contains("Name", tableFromEnumerable.Columns);

    Assert.NotNull(tableFromDictionary);
    Assert.Contains("ID", tableFromDictionary.Columns);
    Assert.Contains("Name", tableFromDictionary.Columns);
    // Note: FromDictionary inserts an empty column at index 0 for the key
    Assert.Equal(3, tableFromDictionary.Columns.Count);

    Assert.NotNull(tableFromDataTable);
    Assert.Contains("ID", tableFromDataTable.Columns);
    Assert.Contains("Name", tableFromDataTable.Columns);
    Assert.Equal(2, tableFromDataTable.Columns.Count);
}

[Fact]
public void ShouldSupportMultipleRenderingFormatsAndOutputRedirection()
{
    // Arrange
    var table = new ConsoleTable("Header");
    table.AddRow("Value");

    // 1. Verify default output redirection to standard console output
    Assert.Equal(System.Console.Out, table.Options.OutputTo);

    // 2. Verify Boxed (Default) format with redirected output
    var boxedWriter = new System.IO.StringWriter();
    table.Configure(o => o.OutputTo = boxedWriter).Write(Format.Default);
    var boxedResult = boxedWriter.ToString();
    Assert.Contains("Header", boxedResult);
    Assert.Contains("|", boxedResult);

    // 3. Verify MarkDown format with redirected output
    var markdownWriter = new System.IO.StringWriter();
    table.Configure(o => o.OutputTo = markdownWriter).Write(Format.MarkDown);
    var markdownResult = markdownWriter.ToString();
    Assert.Contains("| Header |", markdownResult);
    Assert.Contains("|---", markdownResult);

    // 4. Verify Minimal format with redirected output
    var minimalWriter = new System.IO.StringWriter();
    table.Configure(o => o.OutputTo = minimalWriter).Write(Format.Minimal);
    var minimalResult = minimalWriter.ToString();
    Assert.NotEmpty(minimalResult);
    Assert.Contains("Header", minimalResult);
}
